@startuml
skinparam UMLClassBoxStyle fillcolor: #f5f5f5
skinparam UMLActorStyle fillcolor: #f5f5f5
skinparam UMLInterfaceStyle fillcolor: #f5f5f5

class Main {
    +int month
    +int day
    +DateTime()
    +getMonthOfYear()
    +getDayOfWeek()
}

class Month {
    +String name
    +ToText()
}

class Day {
    +String name
    +ToText()
}

Main --> Month
Main --> Day

@enduml
